169	      isConfigured: (account) => account.configured,
170	      describeAccount: (account) =>
171	        describeAccountSnapshot({
172	          account,
173	          configured: account.configured,
174	          extra: {
175	            publicKey: account.publicKey,
176	          },
177	        }),
178	    },
179	    messaging: {
180	      normalizeTarget: (target) => {
181	        // Strip nostr: prefix if present
182	        const cleaned = target.trim().replace(/^nostr:/i, "");
183	        try {
184	          return normalizePubkey(cleaned);
185	        } catch {
186	          return cleaned;
187	        }
188	      },
189	      targetResolver: {
190	        looksLikeId: (input) => {
191	          const trimmed = input.trim();
192	          return trimmed.startsWith("npub1") || /^[0-9a-fA-F]{64}$/.test(trimmed);
193	        },
194	        hint: "<npub|hex pubkey|nostr:npub...>",
195	      },
196	      resolveOutboundSessionRoute: (params) => resolveNostrOutboundSessionRoute(params),
197	    },
198	    status: {
199	      ...createComputedAccountStatusAdapter<ResolvedNostrAccount>({
200	        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
201	        collectStatusIssues: (accounts) => collectStatusIssuesFromLastError("nostr", accounts),
202	        buildChannelSummary: ({ snapshot }) =>
203	          buildPassiveChannelStatusSummary(snapshot, {
204	            publicKey: snapshot.publicKey ?? null,
205	          }),
206	        resolveAccountSnapshot: ({ account, runtime }) => ({
207	          accountId: account.accountId,
208	          name: account.name,
209	          enabled: account.enabled,
210	          configured: account.configured,
211	          extra: {
212	            publicKey: account.publicKey,
213	            profile: account.profile,
214	            ...buildTrafficStatusSummary(runtime),
215	          },
216	        }),
217	      }),
218	    },
219	    gateway: {
220	      startAccount: async (ctx) => {
221	        const account = ctx.account;
222	        ctx.setStatus({
223	          accountId: account.accountId,
224	          publicKey: account.publicKey,
225	        });
226	        ctx.log?.info(
227	          `[${account.accountId}] starting Nostr provider (pubkey: ${account.publicKey})`,
228	        );
229	
230	        if (!account.configured) {
231	          throw new Error("Nostr private key not configured");
232	        }
233	
234	        const runtime = getNostrRuntime();
235	        const pairing = createChannelPairingController({
236	          core: runtime,
237	          channel: "nostr",
238	          accountId: account.accountId,
239	        });
240	        const resolveInboundAccess = async (senderPubkey: string, rawBody: string) =>
241	          await resolveNostrDirectAccess({
242	            cfg: ctx.cfg,
243	            accountId: account.accountId,
244	            dmPolicy: account.config.dmPolicy ?? "pairing",
245	            allowFrom: account.config.allowFrom,
246	            senderPubkey,
247	            rawBody,
248	            runtime: {
249	              shouldComputeCommandAuthorized:
250	                runtime.channel.commands.shouldComputeCommandAuthorized,
251	              resolveCommandAuthorizedFromAuthorizers:
252	                runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
253	            },
254	          });
255	
256	        // Track bus handle for metrics callback
257	        let busHandle: NostrBusHandle | null = null;
258	
259	        const authorizeSender = createPreCryptoDirectDmAuthorizer({
260	          resolveAccess: async (senderPubkey) => await resolveInboundAccess(senderPubkey, ""),
261	          issuePairingChallenge: async ({ senderId, reply }) => {
262	            await pairing.issueChallenge({
263	              senderId,
264	              senderIdLine: `Your Nostr pubkey: ${senderId}`,
265	              sendPairingReply: reply,
266	              onCreated: () => {
267	                ctx.log?.debug?.(`[${account.accountId}] nostr pairing request sender=${senderId}`);
268	              },
269	              onReplyError: (err) => {
270	                ctx.log?.warn?.(
271	                  `[${account.accountId}] nostr pairing reply failed for ${senderId}: ${String(err)}`,
272	                );
273	              },
274	            });
275	          },
276	          onBlocked: ({ senderId, reason }) => {
277	            ctx.log?.debug?.(`[${account.accountId}] blocked Nostr sender ${senderId} (${reason})`);
278	          },
279	        });
280	
281	        const bus = await startNostrBus({
282	          accountId: account.accountId,
283	          privateKey: account.privateKey,
284	          relays: account.relays,
285	          authorizeSender: async ({ senderPubkey, reply }) =>
286	            await authorizeSender({ senderId: senderPubkey, reply }),
287	          onMessage: async (senderPubkey, text, reply, meta) => {
288	            const resolvedAccess = await resolveInboundAccess(senderPubkey, text);
289	            if (resolvedAccess.access.decision !== "allow") {
290	              ctx.log?.warn?.(
291	                `[${account.accountId}] dropping Nostr DM after preflight drift (${senderPubkey}, ${resolvedAccess.access.reason})`,
292	              );
293	              return;
294	            }
295	
296	            await dispatchInboundDirectDmWithRuntime({
297	              cfg: ctx.cfg,
298	              runtime,
299	              channel: "nostr",
300	              channelLabel: "Nostr",
301	              accountId: account.accountId,
302	              peer: {
303	                kind: "direct",
304	                id: senderPubkey,
305	              },
306	              senderId: senderPubkey,
307	              senderAddress: `nostr:${senderPubkey}`,
308	              recipientAddress: `nostr:${account.publicKey}`,
309	              conversationLabel: senderPubkey,
310	              rawBody: text,
311	              messageId: meta.eventId,
312	              timestamp: meta.createdAt * 1000,
313	              commandAuthorized: resolvedAccess.commandAuthorized,
314	              deliver: async (payload) => {
315	                const outboundText =
316	                  payload && typeof payload === "object" && "text" in payload
317	                    ? String((payload as { text?: string }).text ?? "")
318	                    : "";
319	                if (!outboundText.trim()) {
320	                  return;
321	                }
322	                const tableMode = runtime.channel.text.resolveMarkdownTableMode({
323	                  cfg: ctx.cfg,
324	                  channel: "nostr",
325	                  accountId: account.accountId,
326	                });
327	                await reply(runtime.channel.text.convertMarkdownTables(outboundText, tableMode));
328	              },
329	              onRecordError: (err) => {
330	                ctx.log?.error?.(
331	                  `[${account.accountId}] failed recording Nostr inbound session: ${String(err)}`,
332	                );
333	              },
334	              onDispatchError: (err, info) => {
335	                ctx.log?.error?.(
336	                  `[${account.accountId}] Nostr ${info.kind} reply failed: ${String(err)}`,
337	                );
338	              },
339	            });
340	          },
341	          onError: (error, context) => {
342	            ctx.log?.error?.(`[${account.accountId}] Nostr error (${context}): ${error.message}`);
343	          },
344	          onConnect: (relay) => {
345	            ctx.log?.debug?.(`[${account.accountId}] Connected to relay: ${relay}`);
346	          },
347	          onDisconnect: (relay) => {
348	            ctx.log?.debug?.(`[${account.accountId}] Disconnected from relay: ${relay}`);
349	          },
350	          onEose: (relays) => {
351	            ctx.log?.debug?.(`[${account.accountId}] EOSE received from relays: ${relays}`);
352	          },
353	          onMetric: (event: MetricEvent) => {
354	            // Log significant metrics at appropriate levels
355	            if (event.name.startsWith("event.rejected.")) {
356	              ctx.log?.debug?.(
357	                `[${account.accountId}] Metric: ${event.name} ${JSON.stringify(event.labels)}`,
358	              );
359	            } else if (event.name === "relay.circuit_breaker.open") {
360	              ctx.log?.warn?.(
361	                `[${account.accountId}] Circuit breaker opened for relay: ${event.labels?.relay}`,
362	              );
363	            } else if (event.name === "relay.circuit_breaker.close") {
364	              ctx.log?.info?.(
365	                `[${account.accountId}] Circuit breaker closed for relay: ${event.labels?.relay}`,
366	              );
367	            } else if (event.name === "relay.error") {
368	              ctx.log?.debug?.(`[${account.accountId}] Relay error: ${event.labels?.relay}`);
369	            }
370	            // Update cached metrics snapshot
371	            if (busHandle) {
372	              metricsSnapshots.set(account.accountId, busHandle.getMetrics());
373	            }
374	          },
375	        });
376	
377	        busHandle = bus;
378	
379	        // Store the bus handle
380	        activeBuses.set(account.accountId, bus);
381	
382	        ctx.log?.info(
383	          `[${account.accountId}] Nostr provider started, connected to ${account.relays.length} relay(s)`,
384	        );
385	
386	        // Return cleanup function
387	        return {
388	          stop: () => {
389	            bus.close();
390	            activeBuses.delete(account.accountId);
391	            metricsSnapshots.delete(account.accountId);
392	            ctx.log?.info(`[${account.accountId}] Nostr provider stopped`);
393	          },
394	        };
395	      },
396	    },
397	  },
398	  pairing: {
399	    text: {
400	      idLabel: "nostrPubkey",
401	      message: "Your pairing request has been approved!",
402	      normalizeAllowEntry: (entry) => {
403	        try {
404	          return normalizePubkey(entry.trim().replace(/^nostr:/i, ""));
405	        } catch {
406	          return entry.trim();
407	        }
408	      },
409	      notify: async ({ id, message }) => {
410	        // Get the default account's bus and send approval message
411	        const bus = activeBuses.get(DEFAULT_ACCOUNT_ID);
412	        if (bus) {
413	          await bus.sendDm(id, message);
414	        }
415	      },
416	    },
417	  },
418	  security: {
419	    resolveDmPolicy: resolveNostrDmPolicy,
420	  },
421	  outbound: {
422	    deliveryMode: "direct",
423	    textChunkLimit: 4000,
424	    sendText: async ({ cfg, to, text, accountId }) => {
425	      const core = getNostrRuntime();
426	      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
427	      const bus = activeBuses.get(aid);
428	      if (!bus) {
429	        throw new Error(`Nostr bus not running for account ${aid}`);
430	      }
431	      const tableMode = core.channel.text.resolveMarkdownTableMode({
432	        cfg,
433	        channel: "nostr",
434	        accountId: aid,
435	      });
436	      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
437	      const normalizedTo = normalizePubkey(to);
438	      await bus.sendDm(normalizedTo, message);
439	      return attachChannelToResult("nostr", {
440	        to: normalizedTo,
441	        messageId: `nostr-${Date.now()}`,
442	      });
443	    },
444	  },
445	});
446	
447	/**
448	 * Get metrics snapshot for a Nostr account.
449	 * Returns undefined if account is not running.
450	 */
451	export function getNostrMetrics(
452	  accountId: string = DEFAULT_ACCOUNT_ID,
453	): MetricsSnapshot | undefined {
454	  const bus = activeBuses.get(accountId);
455	  if (bus) {
456	    return bus.getMetrics();
457	  }
458	  return metricsSnapshots.get(accountId);
459	}
460	
461	/**
462	 * Get all active Nostr bus handles.
463	 * Useful for debugging and status reporting.
464	 */
465	export function getActiveNostrBuses(): Map<string, NostrBusHandle> {
466	  return new Map(activeBuses);
467	}
468	
469	/**
470	 * Publish a profile (kind:0) for a Nostr account.
471	 * @param accountId - Account ID (defaults to "default")
472	 * @param profile - Profile data to publish
473	 * @returns Publish results with successes and failures
474	 * @throws Error if account is not running
475	 */
476	export async function publishNostrProfile(
477	  accountId: string = DEFAULT_ACCOUNT_ID,
478	  profile: NostrProfile,
479	): Promise<ProfilePublishResult> {
480	  const bus = activeBuses.get(accountId);
481	  if (!bus) {
482	    throw new Error(`Nostr bus not running for account ${accountId}`);
483	  }
484	  return bus.publishProfile(profile);
485	}
486	
487	/**
488	 * Get profile publish state for a Nostr account.
489	 * @param accountId - Account ID (defaults to "default")
490	 * @returns Profile publish state or null if account not running
491	 */
492	export async function getNostrProfileState(accountId: string = DEFAULT_ACCOUNT_ID): Promise<{
493	  lastPublishedAt: number | null;
494	  lastPublishedEventId: string | null;
495	  lastPublishResults: Record<string, "ok" | "failed" | "timeout"> | null;
496	} | null> {
497	  const bus = activeBuses.get(accountId);
498	  if (!bus) {
499	    return null;
500	  }
501	  return bus.getProfileState();
502	}
