import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
// getChatChannelMeta is imported per SDK contract; meta is built as a literal
// because "pulseboard" is not a core ChatChannelId in CHAT_CHANNEL_ORDER.
import {
  createChatChannelPlugin,
  getChatChannelMeta,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/core";
import type { PulseBoardConfig } from "./types.js";

void getChatChannelMeta;

const meta = {
  id: "pulseboard",
  label: "PulseBoard",
  docsPath: "/channels/pulseboard",
  blurb: "real-time bulletin board messaging with boards and direct messages.",
};

type PulseBoardResolvedAccount = {
  accountId: string;
  configured: boolean;
};

function listPulseBoardAccountIds(cfg: { channels?: { pulseboard?: PulseBoardConfig } }): string[] {
  const accounts = cfg.channels?.pulseboard?.accounts;
  if (!accounts || Object.keys(accounts).length === 0) {
    return ["default"];
  }
  return Object.keys(accounts);
}

function resolvePulseBoardAccount(
  cfg: { channels?: { pulseboard?: PulseBoardConfig } },
  accountId?: string | null,
): PulseBoardResolvedAccount {
  const id = accountId ?? "default";
  const account = cfg.channels?.pulseboard?.accounts?.[id];
  return {
    accountId: id,
    configured: Boolean(account?.boardUrl && account?.apiToken && account?.username),
  };
}

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (cfg) => listPulseBoardAccountIds(cfg as Parameters<typeof listPulseBoardAccountIds>[0]),
      resolveAccount: (cfg, accountId) =>
